async function seed() {
  console.log('Seeding Turso database...');
  console.log(`Database URL: ${TursoUrl}`);
  
  let imported = 0;
  const createdAt = new Date().toISOString();

  await client.execute(`
    CREATE TABLE IF NOT EXISTS users (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      username TEXT NOT NULL UNIQUE,
      password TEXT NOT NULL,
      created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
      updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
      deleted_at TEXT
    )
  `);

  await client.execute(`
    CREATE UNIQUE INDEX IF NOT EXISTS users_username_unique
    ON users (username)
  `);

  await client.execute({
    sql: `
      INSERT INTO users (username, password, created_at, updated_at)
      VALUES (?, ?, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP)
      ON CONFLICT(username) DO UPDATE SET
        password = excluded.password,
        updated_at = CURRENT_TIMESTAMP,
        deleted_at = NULL
    `,
    args: [defaultAdmin.username, defaultAdmin.password],
  });

  for (const row of seedData) {
    try {
      await client.execute({
        sql: `INSERT INTO accounts (jev, barangay, date, check_rcd_no, payee, particulars, code, accounts, debit, credit, created_at) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
        args: [
          row.jev || null,
          row.barangay || null,
          row.date || null,
          row.check_rcd_no || null,
          row.payee || null,
          row.particulars || null,
          row.code || null,
          row.account || null,
          row.debit || null,
          row.credit || null,
          createdAt,
        ],
      });
      imported++;
    } catch (error) {
      console.error(`Error inserting row:`, error);
    }
  }

  console.log(`\nSeeding complete!`);
  console.log(`Admin user ensured: ${defaultAdmin.username}`);
  console.log(`Imported: ${imported} rows`);
}

seed().catch(console.error);
